import{a as e,c as t,i as n,n as r,o as i,r as a,s as o,t as s}from"./app-X_Kuuhdi.js";var c=JSON.parse(`{"path":"/os/clipboard_image_kakaotalk_ubuntu.html","title":"우분투 Wine 카카오톡 사진 이미지 스크린샷 붙여넣기","lang":"ko-KR","frontmatter":{"description":"우분투 Wine 카카오톡 사진 이미지 스크린샷 붙여넣기 버전 정보 Ubuntu 24.04 LTS Wine 11.0 핵심 아이디어: Wine 기반 카카오톡은 BMP 포맷만 클립보드 인식이 가능합니다. 리눅스(GNOME Wayland) 환경에서 이미지가 카카오톡에 바로 붙여넣기(Ctrl+V)되지 않아 당황하셨을 겁니다....","permalink":"/os/clipboard_image_kakaotalk_ubuntu","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"우분투 Wine 카카오톡 사진 이미지 스크린샷 붙여넣기\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-07-08T11:03:14.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/os/clipboard_image_kakaotalk_ubuntu"}],["meta",{"property":"og:title","content":"우분투 Wine 카카오톡 사진 이미지 스크린샷 붙여넣기"}],["meta",{"property":"og:description","content":"우분투 Wine 카카오톡 사진 이미지 스크린샷 붙여넣기 버전 정보 Ubuntu 24.04 LTS Wine 11.0 핵심 아이디어: Wine 기반 카카오톡은 BMP 포맷만 클립보드 인식이 가능합니다. 리눅스(GNOME Wayland) 환경에서 이미지가 카카오톡에 바로 붙여넣기(Ctrl+V)되지 않아 당황하셨을 겁니다...."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-07-08T11:03:14.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-08T11:03:14.000Z"}]]},"git":{"createdTime":1765928768000,"updatedTime":1783508594000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":9,"url":"https://github.com/kmbzn"}],"changelog":[{"hash":"a324ae71bd1b6643f0abe3904e241acfc1127c96","time":1783508594000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"Update VuePress to latest rc, restrict pagePatterns to sidebar, and fix image paths"},{"hash":"47b5aed4ca177bf4af7be2a57306ea9a97ab434f","time":1781297335000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"0613_final"},{"hash":"a535bd7abd36d099cb647670a198dfababa695af","time":1778236195000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"docs: update clipboard image guide for KakaoTalk on Ubuntu and refine GRUB font change instructions"},{"hash":"e01266b4355992514a63ef800581dbaed52e8598","time":1778146860000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"update"},{"hash":"3ec211bfba6f3326e2435c5b05b441188c2a995b","time":1778146697000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"clipboard_post_update"},{"hash":"733517276b8fa6f5a5d7e2df44c9df262df667dc","time":1777041291000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: add guide for adjusting GRUB font size using Terminus font on Ubuntu 26.04 LTS"},{"hash":"7771f32dbe3afd0d615bb5b2d0fc4b98ba480168","time":1767211887000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"Refactor code structure for improved readability and maintainability"},{"hash":"f6684f1f7a5eb18e27611d7a52685340be3257c2","time":1766864553000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"update 1228"},{"hash":"37c8ab90effb73c082292c945cb219714d10ba4d","time":1765928768000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"ai final"}]},"filePathRelative":"os/clipboard_image_kakaotalk_ubuntu.md","autoDesc":true}`),l={name:`clipboard_image_kakaotalk_ubuntu.md`},u={class:`print-section`};function d(s,c,l,d,f,p){let m=t(`DateMeta`);return o(),a(`div`,null,[r(`section`,u,[c[0]||=r(`h1`,{id:`우분투-wine-카카오톡-사진-이미지-스크린샷-붙여넣기`,tabindex:`-1`},[r(`a`,{class:`header-anchor`,href:`#우분투-wine-카카오톡-사진-이미지-스크린샷-붙여넣기`},[r(`span`,null,`우분투 Wine 카카오톡 사진 이미지 스크린샷 붙여넣기`)])],-1),i(m),c[1]||=r(`div`,{class:`hint-container info`},[r(`p`,{class:`hint-container-title`},`버전 정보`),r(`p`,null,[e(`Ubuntu 24.04 LTS`),r(`br`),e(` Wine 11.0`)])],-1),c[2]||=r(`blockquote`,null,[r(`p`,null,[r(`em`,null,`핵심 아이디어: Wine 기반 카카오톡은 BMP 포맷만 클립보드 인식이 가능합니다.`)])],-1),c[3]||=r(`p`,null,`리눅스(GNOME Wayland) 환경에서 이미지가 카카오톡에 바로 붙여넣기(Ctrl+V)되지 않아 당황하셨을 겁니다.`,-1),c[4]||=r(`p`,null,`Wine 환경 위에서 돌아가는 카카오톡 PC버전은 구조적으로 붙여넣기 시에 PNG를 인식하지 못하고 오직 BMP 형식만 받아들입니다. 이를 해결하기 위해 캡처와 동시에 파일을 저장하고, 클립보드에 BMP 데이터를 주입하는 명령어를 공유합니다.`,-1)]),c[5]||=n(`<section class="print-section"><h2 id="_1-개요" tabindex="-1"><a class="header-anchor" href="#_1-개요"><span>1. 개요</span></a></h2><ul><li>Wine 카카오톡 호환: 클립보드에 <code>image/bmp</code> 데이터를 포함시켜 카카오톡 복붙 문제를 해결합니다.</li><li>자동 백업: 캡처 즉시 <code>Pictures/Screenshots</code> 폴더에 타임스탬프와 함께 PNG 파일이 저장됩니다.</li><li>범용성: 기본 <code>gnome-screenshot</code> 도구 뿐 아니라 <code>flameshot</code>과 같은 외부 도구도 완벽 지원합니다.</li></ul></section><section class="print-section"><h2 id="_2-필수-패키지-설치" tabindex="-1"><a class="header-anchor" href="#_2-필수-패키지-설치"><span>2. 필수 패키지 설치</span></a></h2><p>터미널에서 변환 및 클립보드 제어를 위한 필수 패키지를 설치해 주세요.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sudo</span> <span class="token function">apt</span> update</span>
<span class="line"><span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> gnome-screenshot copyq</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></section><section class="print-section"><h2 id="_3-환경-변수-설정" tabindex="-1"><a class="header-anchor" href="#_3-환경-변수-설정"><span>3. 환경 변수 설정</span></a></h2><p>CopyQ가 시스템 클립보드에 정상적으로 접근할 수 있도록 환경 변수를 설정해야 합니다.</p><p>먼저 (기존에 실행 중인 CopyQ가 있다면) 종료하고, CopyQ를 X11 호환 레이어(XCB) 모드로 실행해야 합니다. (Wayland 모드의 경우 보안 정책에 따라 작동하지 않게 됩니다.)</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">copyq <span class="token builtin class-name">exit</span></span>
<span class="line"><span class="token builtin class-name">export</span> <span class="token assign-left variable">QT_QPA_PLATFORM</span><span class="token operator">=</span>xcb</span>
<span class="line">copyq <span class="token operator">&amp;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></section><section class="print-section"><h2 id="_4-최종-명령어-단축키-등록용" tabindex="-1"><a class="header-anchor" href="#_4-최종-명령어-단축키-등록용"><span>4. 최종 명령어 (단축키 등록용)</span></a></h2><p>터미널에서 실행하거나 단축키에 등록할 최종 명령어입니다. 지정한 영역을 캡처하여 파일로 저장하고, 그 파일 데이터를 CopyQ를 통해 클립보드에 이미지(<code>image/png</code>) 형식으로 밀어 넣습니다.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">sh</span> <span class="token parameter variable">-c</span> <span class="token string">&#39;d=~/Pictures/Screenshots; f=&quot;$d/screenshot_$(date +%Y%m%d_%H%M%S).png&quot;; mkdir -p &quot;$d&quot;; gnome-screenshot -af &quot;$f&quot; &amp;&amp; (copyq p _ || (QT_QPA_PLATFORM=xcb copyq &amp; sleep 0.5)) &amp;&amp; copyq copy image/png - &lt; &quot;$f&quot;&#39;</span> </span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li><code>gnome-screenshot -a</code>: 마우스로 캡처 영역을 선택합니다.</li><li><code>[ -s &quot;$f&quot; ]</code>: 캡처가 정상적으로 완료되어 파일이 생성되었는지 확인합니다.</li><li><code>&lt; &quot;$f&quot;</code>: 실제 이미지 파일의 바이너리 데이터를 CopyQ로 전달합니다.</li></ul></section><section class="print-section"><h2 id="_5-우분투-키보드-단축키-등록-방법" tabindex="-1"><a class="header-anchor" href="#_5-우분투-키보드-단축키-등록-방법"><span>5. 우분투 키보드 단축키 등록 방법</span></a></h2><p>위 명령어를 매번 터미널에 칠 수는 없으니, 키보드 단축키로 등록해 보겠습니다.</p><ol><li>우분투 설정(Settings) 앱을 엽니다.</li><li>왼쪽 사이드바에서 키보드(Keyboard)를 선택합니다.</li><li>단축키 보기 및 사용자 설정(View and Customize Shortcuts)을 클릭합니다.</li><li>목록 맨 아래의 사용자 설정 단축키(Custom Shortcuts)를 선택합니다.</li><li><ul><li>(추가) 버튼을 누르고 아래 내용을 입력합니다.</li></ul><ul><li>이름: <code>영역 캡처 후 클립보드 복사</code></li><li>명령어: 위 4번 섹션의 <code>sh -c &#39;...&#39;</code> 전체 명령어를 복사해서 붙여넣습니다.</li><li>단축키: 원하는 키 조합을 누릅니다 (예: <code>PrintScreen</code>).</li></ul></li><li>X를 눌러 창을 닫습니다.</li></ol></section><section class="print-section"><h2 id="_6-작동-확인" tabindex="-1"><a class="header-anchor" href="#_6-작동-확인"><span>6. 작동 확인</span></a></h2><p>이제 설정한 단축키를 눌러 영역을 선택해 보세요. 지정한 경로에 파일이 생성됨과 동시에, 카카오톡 채팅창에서 <code>Ctrl + V</code>를 누르면 방금 찍은 스크린샷이 이미지 형태로 바로 붙여넣을 수 있게 됩니다.</p><p>현재 클립보드 상태를 확인하고 싶다면 터미널에 <code>wl-paste -l</code>을 입력했을 때 <code>image/png</code>가 목록에 보이면 <strong>성공</strong>입니다.</p><p><img src="/assets/paste-BncfWIB9.webp" alt=""></p><blockquote><p><em>이제 캡처 후 바로 카카오톡 대화창에서 <code>Ctrl+V</code>를 눌러보세요.</em><br><em>깔끔하게 전송되는 것을 확인하실 수 있습니다.</em></p></blockquote></section>`,6)])}var f=s(l,[[`render`,d]]);export{c as _pageData,f as default};